import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.players = {}  # player_id -> websocket
        self.inventories = defaultdict(dict)  # player_id -> {item_id: quantity}
        self.lock = asyncio.Lock()

    async def register(self, websocket, player_id):
        self.players[player_id] = websocket
        await self.send_inventory(player_id)

    async def unregister(self, player_id):
        del self.players[player_id]

    async def send_inventory(self, player_id):
        inventory = self.inventories[player_id]
        await self.players[player_id].send(json.dumps({'type': 'inventory', 'items': inventory}))

    async def handle_trade(self, player_id, data):
        async with self.lock:
            from_player = player_id
            to_player = data['to_player']
            item_id = data['item_id']
            quantity = data['quantity']

            if self.inventories[from_player].get(item_id, 0) >= quantity:
                self.inventories[from_player][item_id] -= quantity
                if self.inventories[from_player][item_id] == 0:
                    del self.inventories[from_player][item_id]

                if item_id in self.inventories[to_player]:
                    self.inventories[to_player][item_id] += quantity
                else:
                    self.inventories[to_player][item_id] = quantity

                await self.send_inventory(from_player)
                await self.send_inventory(to_player)

    async def handler(self, websocket, path):
        player_id = await websocket.recv()
        await self.register(websocket, player_id)
        try:
            async for message in websocket:
                data = json.loads(message)
                if data['type'] == 'trade':
                    await self.handle_trade(player_id, data)
        finally:
            await self.unregister(player_id)

    async def main(self):
        async with websockets.serve(self.handler, "localhost", 8765):
            await asyncio.Future()  # run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.main())